import{_ as l,o as n,c as s,a2 as i}from"./chunks/framework.BnBoz4Zl.js";const u=JSON.parse('{"title":"第 15 章 信息收集、人工筛选、复核与发布","description":"稳定的信息任务不是“每天自动抓很多内容”，而是先定义范围，再把候选、筛选、核验、确认和发布分开。本章只提供通用方法，不展示任何真实刊物、渠道或反馈数据。 建立一条有人把关的信息链：来源清楚、候选充分、筛选有理由、事实可核验、发布需确认、反馈能改进下一次。","frontmatter":{},"headers":[],"relativePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 15 章 资讯整合：把信息流变成每日通知/index.md","filePath":"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 15 章 资讯整合：把信息流变成每日通知/index.md","lastUpdated":1784770175000}'),e={name:"bluebook/第二篇 案例篇：从一项任务到一支 AI 团队/第 15 章 资讯整合：把信息流变成每日通知/index.md"};function t(o,a,r,p,h,d){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="第-15-章-信息收集、人工筛选、复核与发布" tabindex="-1">第 15 章 信息收集、人工筛选、复核与发布 <a class="header-anchor" href="#第-15-章-信息收集、人工筛选、复核与发布" aria-label="Permalink to &quot;第 15 章 信息收集、人工筛选、复核与发布&quot;">​</a></h1><p>稳定的信息任务不是“每天自动抓很多内容”，而是先定义范围，再把候选、筛选、核验、确认和发布分开。本章只提供通用方法，不展示任何真实刊物、渠道或反馈数据。</p><h2 id="可应用到哪些任务" tabindex="-1">可应用到哪些任务 <a class="header-anchor" href="#可应用到哪些任务" aria-label="Permalink to &quot;可应用到哪些任务&quot;">​</a></h2><ul><li>政策、行业和公开信息跟踪。</li><li>内部简报、专题资料和会议参考材料。</li><li>公开舆情、合作方动态或技术更新整理。</li><li>培训资料和知识分享候选内容收集。</li></ul><h2 id="任务目标" tabindex="-1">任务目标 <a class="header-anchor" href="#任务目标" aria-label="Permalink to &quot;任务目标&quot;">​</a></h2><p>建立一条有人把关的信息链：来源清楚、候选充分、筛选有理由、事实可核验、发布需确认、反馈能改进下一次。</p><h2 id="输入材料" tabindex="-1">输入材料 <a class="header-anchor" href="#输入材料" aria-label="Permalink to &quot;输入材料&quot;">​</a></h2><ul><li>主题、时间范围、读者和使用目的。</li><li>允许使用的信息源和禁止来源。</li><li>筛选标准、数量范围和输出格式。</li><li>事实核验要求、确认人和发布边界。</li></ul><h2 id="执行步骤" tabindex="-1">执行步骤 <a class="header-anchor" href="#执行步骤" aria-label="Permalink to &quot;执行步骤&quot;">​</a></h2><ol><li><strong>定义范围</strong>：把主题、时间、来源和排除项写成规则。</li><li><strong>形成候选池</strong>：先保证覆盖，再按相关性、可信度和时效性排序。</li><li><strong>人工筛选</strong>：保留、删除、补充和调整顺序，由负责人明确确认。</li><li><strong>事实复核</strong>：打开原始来源核对标题、日期、主体和关键事实。</li><li><strong>生成发布稿</strong>：摘要与评论分开，保留原始链接和来源日期。</li><li><strong>记录反馈</strong>：保存本次取舍理由，为下一次提供偏好，但不把一次选择当永久规则。</li></ol><h2 id="合成示例" tabindex="-1">合成示例 <a class="header-anchor" href="#合成示例" aria-label="Permalink to &quot;合成示例&quot;">​</a></h2><p>任务是整理“本周办公数字化公开资讯”。WorkBuddy 收集十二条候选并按主题分类；经办人确认保留六条后，系统再生成摘要。没有明确确认，不进入发布步骤。</p><h3 id="可复制任务模板" tabindex="-1">可复制任务模板 <a class="header-anchor" href="#可复制任务模板" aria-label="Permalink to &quot;可复制任务模板&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请建立一次信息收集与筛选任务。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：{主题}</span></span>
<span class="line"><span>时间范围：{日期}</span></span>
<span class="line"><span>目标读者：{读者}</span></span>
<span class="line"><span>允许来源：{来源范围}</span></span>
<span class="line"><span>禁止来源：{来源或类型}</span></span>
<span class="line"><span>候选数量：{数量}</span></span>
<span class="line"><span>筛选标准：相关性、可信度、时效性、可行动性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请先输出候选清单，包含标题、来源、日期、链接、摘要和入选理由。</span></span>
<span class="line"><span>等待我明确完成筛选后，再核验保留项并生成发布草稿。</span></span>
<span class="line"><span>不得自动发布，不得把模型推断写成新闻事实。</span></span></code></pre></div><h2 id="人工确认点" tabindex="-1">人工确认点 <a class="header-anchor" href="#人工确认点" aria-label="Permalink to &quot;人工确认点&quot;">​</a></h2><ul><li>来源是否允许使用且可以回查。</li><li>候选是否覆盖充分，筛选标准是否一致。</li><li>摘要是否忠于原文，评论是否明确标注。</li><li>是否已收到明确的发布确认。</li></ul><h2 id="输出物与验收标准" tabindex="-1">输出物与验收标准 <a class="header-anchor" href="#输出物与验收标准" aria-label="Permalink to &quot;输出物与验收标准&quot;">​</a></h2><ul><li>候选池与筛选结果分开保存。</li><li>每条信息有原始来源、日期和核验状态。</li><li>发布稿不包含无来源事实和内部敏感内容。</li><li>本次反馈可追踪，但不会自动覆盖长期规则。</li></ul><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>候选太少会把筛选变成被动接受，应先形成足够候选。</li><li>用定时轮询代替人的明确确认，可能误触发发布。确认必须显式。</li><li>只看二手摘要容易放大错误，应回到原始来源核验。</li><li>不自动发布、不抓取受限内容、不公开内部筛选记录。可复用来源表、筛选表、核验表和发布检查表。</li></ul>`,20)])])}const b=l(e,[["render",t]]);export{u as __pageData,b as default};
